mapper.update:
UPDATE jsh_price_approval
SET delivery_date=#{deliveryDate}, remark=#{remark},
    total_weight=#{totalWeight}, total_amount=#{totalAmount},
    status=#{status}, update_time=#{updateTime}, updater=#{updater},
    delete_flag=#{deleteFlag}
WHERE id=#{id}

mapper.sql:
FROM jsh_price_approval pa
JOIN jsh_depot_head dh ON dh.id = pa.depot_head_id
LEFT JOIN jsh_supplier s ON s.id = pa.organ_id
WHERE ifnull(pa.delete_flag,'0') != '1'

    AND pa.organ_id = #{organId}


    AND pa.status = #{status}


    AND dh.number LIKE concat('%', #{billNo}, '%')


    AND dh.oper_time >= #{beginTime}


    AND dh.oper_time <= #{endTime}

mapper.select:
SELECT pa.id, pa.approval_no as approvalNo, dh.number as billNo, DATE_FORMAT(dh.oper_time,'%Y-%m-%d') as billTimeStr, s.supplier as customerName, s.project_name as projectName, DATE_FORMAT(pa.delivery_date,'%Y-%m-%d') as deliveryDateStr, pa.total_weight as totalWeight, pa.total_amount as totalAmount, pa.status, pa.remark, DATE_FORMAT(pa.create_time,'%Y-%m-%d %H:%i:%s') as createTimeStr, pa.depot_head_id as depotHeadId, dh.file_name as fileName
ORDER BY pa.create_time DESC
LIMIT #{offset}, #{rows}

mapper.update:
UPDATE jsh_price_approval_item
weight=#{weight}, all_price=#{allPrice}, tax_money=#{taxMoney}, tax_last_money=#{taxLastMoney}, remark=#{remark}, delete_flag=#{deleteFlag},
WHERE id=#{id}

mapper.sql:
WHERE dh.type = '出库' AND dh.sub_type = '销售'
  AND dh.status = '1'
  AND ifnull(dh.delete_flag,'0') != '1'
  AND dh.id NOT IN (
    SELECT pa.depot_head_id FROM jsh_price_approval pa
    WHERE ifnull(pa.delete_flag,'0') != '1'
  )

    AND dh.organ_id = #{organId}


    AND dh.number LIKE concat('%', #{billNo}, '%')


    AND dh.oper_time >= #{beginTime}


    AND dh.oper_time <= #{endTime}
